import csv
import json

def _normalize_and_filter(rows):
    results = []
    for row in rows:
        name = row['name'].strip().title()
        email = row['email'].strip().lower()
        age = int(row['age'])
        if age >= 18 and '@' in email:
            results.append({'name': name, 'email': email, 'age': age})
    return results

def process_csv(path):
    with open(path) as f:
        reader = csv.DictReader(f)
        return _normalize_and_filter(reader)

def process_json(path):
    with open(path) as f:
        data = json.load(f)
        return _normalize_and_filter(data)
```

